def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0.0
        decay = 1.0
        for j in range(1, 10):
            if j % 2 == 0:
                decay *= 0.9
            else:
                decay *= 1.05
            if ratio < 0.05 * j:
                score += (j ** 3) * (1 - ratio) * decay
            else:
                score += (np.sin(ratio * j * np.pi) + 1) * (j**1.5) * decay / (j + 1)
            if cap % (j + 1) == 0:
                score *= 1.03
            elif cap % j == 1:
                score *= 0.97
        remainder = cap % int(item) if item != 0 else cap
        if remainder == 0:
            for k in range(1, 5):
                val = cap / (k + ratio + 1)
                score += np.tanh(val) * (k * 0.5)
        else:
            for k in range(1, 4):
                val = abs(remainder - k * ratio * 10)
                score -= np.log1p(val + 1) / (k + 1)
        if score > 0:
            priorities[i] = -score / (cap * 0.5 + 1)
        else:
            priorities[i] = -score * np.sqrt(cap + 2)
    return priorities
